)}
          
          {/* Show recent reviews preview */}
          {hotel.reviews && hotel.reviews.length > 0 && (
            <div className="mb-3 p-2 bg-white/5 rounded-lg border border-white/5">
              <div className="flex items-center gap-1 mb-1">
